using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Orders;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    #region Helper

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] entries) =>
        entries.Select(e => new OrderItem
        {
            ProductName = e.Name,
            Price = e.Price,
            Quantity = e.Qty
        }).ToList();

    #endregion

    // ──────────────────────────────────────────────
    //  CreateOrder – Happy Path
    // ──────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 9.99m, 3));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(29.97m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfPriceTimesQuantity()
    {
        // Arrange
        var items = CreateItems(
            ("Widget", 10.00m, 2),   // 20.00
            ("Gadget", 5.50m, 4));   // 22.00

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(42.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCustomerId()
    {
        // Arrange
        var items = CreateItems(("Widget", 1.00m, 1));

        // Act
        var order = _sut.CreateOrder("cust-42", items);

        // Assert
        Assert.AreEqual("cust-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsItemsReference()
    {
        // Arrange
        var items = CreateItems(("Widget", 1.00m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_GeneratesNonEmptyId()
    {
        // Arrange
        var items = CreateItems(("Widget", 1.00m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToApproximatelyUtcNow()
    {
        // Arrange
        var items = CreateItems(("Widget", 1.00m, 1));
        var before = DateTime.UtcNow;

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt:O} should be between {before:O} and {after:O}.");
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_GeneratesUniqueIds()
    {
        // Arrange
        var items = CreateItems(("Widget", 1.00m, 1));

        // Act
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_OrderIsRetrievableViaGetOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));

        // Act
        var created = _sut.CreateOrder("cust-1", items);
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    // ──────────────────────────────────────────────
    //  CreateOrder – Total Calculation (Parameterized)
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(1.00, 1, 1.00, DisplayName = "1 × $1.00 = $1.00")]
    [DataRow(7.50, 2, 15.00, DisplayName = "2 × $7.50 = $15.00")]
    [DataRow(0.01, 100, 1.00, DisplayName = "100 × $0.01 = $1.00")]
    [DataRow(99.99, 1, 99.99, DisplayName = "1 × $99.99 = $99.99")]
    public void CreateOrder_SingleItemVariousQuantities_CalculatesCorrectTotal(
        double price, int quantity, double expectedTotal)
    {
        // Arrange
        var items = CreateItems(("Product", (decimal)price, quantity));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    // ──────────────────────────────────────────────
    //  CreateOrder – Error Cases
    // ──────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateItems(("Widget", 1.00m, 1));

        // Act & Assert
        var ex = Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", items));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // ──────────────────────────────────────────────
    //  GetOrder
    // ──────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
        Assert.AreEqual("cust-1", result.CustomerId);
        Assert.AreEqual(5.00m, result.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_MultipleOrders_ReturnsCorrectOne()
    {
        // Arrange
        var order1 = _sut.CreateOrder("cust-1", CreateItems(("A", 1.00m, 1)));
        var order2 = _sut.CreateOrder("cust-2", CreateItems(("B", 2.00m, 1)));
        var order3 = _sut.CreateOrder("cust-3", CreateItems(("C", 3.00m, 1)));

        // Act
        var result = _sut.GetOrder(order2.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(order2.Id, result.Id);
        Assert.AreEqual("cust-2", result.CustomerId);
    }

    // ──────────────────────────────────────────────
    //  GetOrdersByCustomer
    // ──────────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_CustomerHasOrders_ReturnsAllMatching()
    {
        // Arrange
        _sut.CreateOrder("cust-1", CreateItems(("A", 1.00m, 1)));
        _sut.CreateOrder("cust-1", CreateItems(("B", 2.00m, 1)));
        _sut.CreateOrder("cust-2", CreateItems(("C", 3.00m, 1)));

        // Act
        var results = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(2, results.Count);
        Assert.IsTrue(results.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoMatchingOrders_ReturnsEmptyList()
    {
        // Arrange
        _sut.CreateOrder("cust-1", CreateItems(("A", 1.00m, 1)));

        // Act
        var results = _sut.GetOrdersByCustomer("unknown-customer");

        // Assert
        Assert.AreEqual(0, results.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_EmptyService_ReturnsEmptyList()
    {
        // Act
        var results = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(0, results.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleCustomers_ReturnsOnlyRequestedCustomerOrders()
    {
        // Arrange
        var orderA = _sut.CreateOrder("cust-A", CreateItems(("X", 10.00m, 1)));
        _sut.CreateOrder("cust-B", CreateItems(("Y", 20.00m, 1)));
        var orderC = _sut.CreateOrder("cust-A", CreateItems(("Z", 30.00m, 1)));

        // Act
        var results = _sut.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.AreEqual(2, results.Count);
        CollectionAssert.AreEquivalent(
            new[] { orderA.Id, orderC.Id },
            results.Select(o => o.Id).ToArray());
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsReadOnlyList()
    {
        // Arrange
        _sut.CreateOrder("cust-1", CreateItems(("A", 1.00m, 1)));

        // Act
        var results = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.IsInstanceOfType<IReadOnlyList<Order>>(results);
    }
}

