 using Microsoft.VisualStudio.TestTools.UnitTesting;

 namespace Contoso.Orders;

 [TestClass]
 public sealed class OrderServiceTests
 {
     private OrderService _sut = null!;

     [TestInitialize]
     public void Setup()
     {
         _sut = new OrderService();
     }

     #region Helper

     private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] entries) =>
         entries.Select(e => new OrderItem
         {
             ProductName = e.Name,
             Price = e.Price,
             Quantity = e.Qty
         }).ToList();

     #endregion

     // ──────────────────────────────────────────────
     //  CreateOrder – Happy Path
     // ──────────────────────────────────────────────

     [TestMethod]
     public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
     {
         // Arrange
         var items = CreateItems(("Widget", 9.99m, 3));

         // Act
         var order = _sut.CreateOrder("cust-1", items);

         // Assert
         Assert.AreEqual(29.97m, order.Total);
     }

     [TestMethod]
     public void CreateOrder_MultipleItems_ReturnsSumOfPriceTimesQuantity()
     {
         // Arrange
         var items = CreateItems(
             ("Widget", 10.00m, 2),   // 20.00
             ("Gadget", 5.50m, 4));   // 22.00

         // Act
         var order = _sut.CreateOrder("cust-1", items);

         // Assert
         Assert.AreEqual(42.00m, order.Total);
     }

     [TestMethod]
     public void CreateOrder_ValidInput_SetsCustomerId()
     {
         // Arrange
         var items = CreateItems(("Widget", 1.00m, 1));

         // Act
         var order = _sut.CreateOrder("cust-42", items);

         // Assert
         Assert.AreEqual("cust-42", order.CustomerId);
     }

     [TestMethod]
     public void CreateOrder_ValidInput_SetsItemsReference()
     {
         // Arrange
         var items = CreateItems(("Widget", 1.00m, 1));

         // Act
         var order = _sut.CreateOrder("cust-1", items);

         // Assert
         Assert.AreSame(items, order.Items);
     }

     [TestMethod]
     public void CreateOrder_ValidInput_GeneratesNonEmptyId()
     {
         // Arrange
         var items = CreateItems(("Widget", 1.00m, 1));

         // Act
         var order = _sut.CreateOrder("cust-1", items);

         // Assert
         Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
     }

     [TestMethod]
     public void CreateOrder_ValidInput_SetsCreatedAtToApproximatelyUtcNow()
     {
         // Arrange
         var items = CreateItems(("Widget", 1.00m, 1));
         var before = DateTime.UtcNow;

         // Act
         var order = _sut.CreateOrder("cust-1", items);

         // Assert
         var after = DateTime.UtcNow;
         Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
             $"CreatedAt {order.CreatedAt:O} should be between {before:O} and {after:O}.");
     }

